/**
 * Data loader for University Dean Dashboard.
 * Imports pre-processed JSON files generated by preprocess_excel.py
 * (which reads Excel sheets from src/assets/ using pandas).
 */
import dashboardData from './dashboardData.json';
import rawPublications from './rawPublications.json';
import allFaculty from './allFaculty.json';

/**
 * Returns the raw parsed data (publications + faculty).
 * Kept async for backward-compatibility with existing callers.
 */
export async function loadExcelData() {
  return {
    instituteSummary: [],
    allFaculty,
    publications: rawPublications,
  };
}

/**
 * Returns all aggregated data expected by UniversityDeanDashboard.jsx.
 * The heavy aggregation is now done at build-time by the Python script.
 */
export function aggregateUniversityData() {
  return {
    ...dashboardData,
    rawPublications,
    allFaculty,
  };
}
